#include <bits/stdc++.h>using namespace std; // macros#define ll long long#define yes cout << "YES\n"#define no cout << "NO\n"#define f(i, size) for (int i = 0; i < size; i++)// #define ia(a, n) \//     int a[n];     \//     f(i, n) cin >> a[i] #define iv(v, n)     \    vector<ll> v(n); \    f(i, n) cin >> v[i] // #define M (1000000007)#define INF 1000000000000000000LL#define mp make_pair#define mt make_tuple #define nline '\n'#define pb push_back#define pii pair<int, int>#define pll pair<ll, ll>#define vii vector<pair<int, int>> void solve() {    ll n; cin>>n;    string s;    cin>>s;    if(n&1) {no; return;}    // consider a string , or jab strign ka last char match karega pop kardo nhi toh add kardo , after traversal string empty ho chahiye     string str="";    for(int i=0; i<n; i++){        if(str.size()==0 || str.back()!=s[i]) str+=s[i];        else str.pop_back();    }    (str.size()==0) ? yes : no;} int main(){    ios::sync_with_stdio(false);    cin.tie(nullptr);    cout.tie(nullptr);     ll t;    cin >> t;    while (t--) {        solve();    }    return 0;}